import{c as h,S as t,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Hóa đơn","description":"","frontmatter":{},"headers":[],"relativePath":"admin/hoa-don.md","filePath":"admin/hoa-don.md","lastUpdated":0}'),o={name:"admin/hoa-don.md"};function l(c,n,e,r,g,s){return t(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="hoa-đon" tabindex="-1">Hóa đơn <a class="header-anchor" href="#hoa-đon" aria-label="Permalink to “Hóa đơn”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/business/receipt</code></p><p>Quản lý toàn bộ hóa đơn (receipt) phát sinh trong hệ thống: học viên mua khóa, gia hạn, mua bộ đề, mua học liệu…</p><h2 id="danh-sach-hoa-đon" tabindex="-1">Danh sách hóa đơn <a class="header-anchor" href="#danh-sach-hoa-đon" aria-label="Permalink to “Danh sách hóa đơn”">​</a></h2><p>Cột chính:</p><ul><li><strong>Mã hóa đơn</strong> (vd <code>HD20260512001</code>)</li><li><strong>Học viên</strong> (tên, SĐT)</li><li><strong>Tổng tiền</strong> trước khuyến mãi</li><li><strong>Khuyến mãi</strong> (nếu có)</li><li><strong>Số tiền thực thu</strong></li><li><strong>Phương thức thanh toán</strong> (Chuyển khoản / VNPay / Momo / Tiền mặt…)</li><li><strong>Trạng thái</strong>: <ul><li><code>Chờ thanh toán</code> (vừa tạo)</li><li><code>Đã thanh toán</code> (đã đối soát thành công)</li><li><code>Đã hủy</code></li><li><code>Hoàn tiền</code></li></ul></li><li><strong>Ngày tạo</strong>, <strong>Ngày thanh toán</strong></li><li>Đại lý / Giáo viên giới thiệu (nếu có)</li></ul><h2 id="bo-loc-tim-kiem" tabindex="-1">Bộ lọc &amp; tìm kiếm <a class="header-anchor" href="#bo-loc-tim-kiem" aria-label="Permalink to “Bộ lọc &amp; tìm kiếm”">​</a></h2><ul><li>Theo trạng thái</li><li>Theo phương thức thanh toán</li><li>Theo khoảng ngày</li><li>Theo học viên (SĐT / tên)</li><li>Theo khóa học có trong đơn</li><li>Theo đại lý / giáo viên giới thiệu</li></ul><h2 id="xem-chi-tiet-hoa-đon" tabindex="-1">Xem chi tiết hóa đơn <a class="header-anchor" href="#xem-chi-tiet-hoa-đon" aria-label="Permalink to “Xem chi tiết hóa đơn”">​</a></h2><p><code>https://lamsonedutech.vn/admin/business/detailreceipt/:id</code></p><p>Trang chi tiết hiển thị:</p><ul><li>Thông tin học viên</li><li>Danh sách khóa học / sản phẩm trong đơn</li><li>Giá từng dòng, tổng tiền</li><li>Mã khuyến mãi áp dụng</li><li>Phương thức + biên lai (ảnh chứng từ chuyển khoản nếu có)</li><li>Lịch sử thay đổi trạng thái</li></ul><h2 id="xac-nhan-thanh-toan-thu-cong" tabindex="-1">Xác nhận thanh toán thủ công <a class="header-anchor" href="#xac-nhan-thanh-toan-thu-cong" aria-label="Permalink to “Xác nhận thanh toán thủ công”">​</a></h2><p>Khi học viên chuyển khoản trực tiếp (không qua cổng thanh toán):</p><ol><li>Học viên gửi ảnh chứng từ qua hotline / Zalo.</li><li>Admin / nhân viên kế toán mở hóa đơn → tab <strong>Thanh toán</strong>.</li><li>Tải lên ảnh chứng từ, ghi chú số tài khoản nhận.</li><li>Bấm <strong>Xác nhận thanh toán</strong> → hệ thống đổi trạng thái sang <strong>Đã thanh toán</strong>.</li><li>Hệ thống tự động kích hoạt khóa học cho học viên (xem <a href="./hoc-vien-khoa-hoc">Học viên - Khóa học</a>).</li></ol><h2 id="huy-hoa-đon" tabindex="-1">Hủy hóa đơn <a class="header-anchor" href="#huy-hoa-đon" aria-label="Permalink to “Hủy hóa đơn”">​</a></h2><ul><li>Bấm <strong>Hủy</strong> trên dòng.</li><li>Chỉ hủy được đơn ở trạng thái <code>Chờ thanh toán</code>.</li><li>Đối với đơn đã thanh toán → dùng <strong>Hoàn tiền</strong> thay vì hủy.</li></ul><h2 id="hoan-tien" tabindex="-1">Hoàn tiền <a class="header-anchor" href="#hoan-tien" aria-label="Permalink to “Hoàn tiền”">​</a></h2><ol><li>Bấm <strong>Hoàn tiền</strong> trên hóa đơn đã thanh toán.</li><li>Nhập số tiền hoàn (có thể hoàn toàn phần hoặc 1 phần).</li><li>Nhập lý do.</li><li>Xác nhận → hệ thống: <ul><li>Đổi trạng thái thành <strong>Hoàn tiền</strong>.</li><li>Thu hồi quyền học của khóa tương ứng (xem <a href="./hoc-vien-khoa-hoc">Học viên - Khóa học</a>).</li><li>Kế toán thực hiện hoàn tiền thực tế ngoài hệ thống.</li></ul></li></ol><h2 id="in-hoa-đon-xuat-pdf" tabindex="-1">In hóa đơn / Xuất PDF <a class="header-anchor" href="#in-hoa-đon-xuat-pdf" aria-label="Permalink to “In hóa đơn / Xuất PDF”">​</a></h2><ul><li>Mở chi tiết hóa đơn → bấm <strong>In hóa đơn</strong> → hiển thị bản in chuẩn.</li><li>Hoặc <strong>Xuất PDF</strong> để gửi qua email cho học viên.</li></ul><h2 id="đoi-soat-voi-cong-thanh-toan" tabindex="-1">Đối soát với cổng thanh toán <a class="header-anchor" href="#đoi-soat-voi-cong-thanh-toan" aria-label="Permalink to “Đối soát với cổng thanh toán”">​</a></h2><p>Nếu hệ thống tích hợp <strong>VNPay / Momo / ZaloPay / OnePay</strong>:</p><ul><li>Trạng thái thanh toán <strong>tự cập nhật</strong> khi cổng thanh toán callback thành công.</li><li>Trường hợp callback lỗi, có thể bấm <strong>Kiểm tra lại</strong> để gọi API truy vấn.</li></ul><h2 id="bao-cao-doanh-thu" tabindex="-1">Báo cáo doanh thu <a class="header-anchor" href="#bao-cao-doanh-thu" aria-label="Permalink to “Báo cáo doanh thu”">​</a></h2><ul><li>Vào <a href="./thong-ke#_1-thong-ke-khoa-hoc">Thống kê → Khóa học</a> để xem doanh thu tổng quan.</li><li>Xuất Excel hóa đơn theo bộ lọc để báo cáo kế toán hàng tháng.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên báo &quot;đã chuyển tiền nhưng chưa được mở khóa&quot;.</strong> → Tra hóa đơn theo SĐT. Nếu trạng thái còn <strong>Chờ thanh toán</strong>, đối soát ngân hàng và xác nhận thủ công.</p><p><strong>Học viên xin xuất hóa đơn VAT đỏ.</strong> → Liên hệ kế toán xuất ngoài hệ thống. Hệ thống chỉ cung cấp <strong>biên nhận điện tử</strong> mặc định.</p><p><strong>Tạo hóa đơn thủ công cho học viên offline?</strong> → Bấm <strong>Tạo hóa đơn</strong> → chọn học viên + khóa + nhập tiền và phương thức. Phù hợp khi học viên đóng tiền mặt tại văn phòng.</p>',30)])])}const m=h(o,[["render",l]]);export{u as __pageData,m as default};
